func (a *App) startup(ctx context.Context) {
	a.ctx = ctx

	homeDir, err := os.UserHomeDir()
	if err != nil {
		fmt.Printf("Failed to get home dir: %v\n", err)
		return
	}

	dataDir := filepath.Join(homeDir, ".still_wtzn")

	if err := os.MkdirAll(dataDir, 0755); err != nil {
		fmt.Printf("Failed to create data dir: %v\n", err)
		return
	}

	if err := initDB(dataDir); err != nil {
		fmt.Printf("Failed to init db: %v\n", err)
		return
	}
}

func (a *App) shutdown(ctx context.Context) {
	closeDB()
}

func (a *App) GetDataDir() string {
	homeDir, _ := os.UserHomeDir()
	return filepath.Join(homeDir, ".still_wtzn")
}

func (a *App) GetFragmentPool() []Fragment {
	return fragmentPool
}

func (a *App) GetFragments(page, pageSize int) (*PaginatedResult, error) {
	rows, err := db.Query("SELECT full_title FROM collected")
	if err != nil {
		return nil, fmt.Errorf("query collected full_title failed: %w", err)
	}
	defer rows.Close()

	collectedMap := make(map[string]bool)
	for rows.Next() {
		var t string
		if err := rows.Scan(&t); err != nil {
			continue
		}
		collectedMap[t] = true
	}

	seed := time.Now().UnixNano()
	rng := newSeededRandom(seed)

	pool := slices.Clone(fragmentPool)

	selected := []Fragment{}

	for len(selected) < 1 && len(pool) > 0 {
		idx := int(rng.Float64() * float64(len(pool)))
		frag := pool[idx]
		pool = append(pool[:idx], pool[idx+1:]...)
		if collectedMap[frag.FullTitle] {
			continue
		}
		frag.PositionX = 5 + rng.Float64()*60
		frag.PositionY = 8 + rng.Float64()*75
		frag.Angle = rng.Float64()*30 - 15
		selected = append(selected, frag)
	}

	if len(selected) == 0 {
		println("GetFragments: WARNING - no fragments selected!")
	}
	return paginatedSlice(selected, len(selected), page, pageSize), nil
}

func newSeededRandom(seed int64) *rand.Rand {
	return rand.New(rand.NewPCG(uint64(seed), uint64(seed)))
}

func (a *App) LoadCollected(page, pageSize int) (*PaginatedResult, error) {
	fragments, total, err := dbLoadCollected(page, pageSize)
	if err != nil {
		return nil, err
	}
	return paginatedSlice(fragments, total, page, pageSize), nil
}

func (a *App) SaveFragment(frag Fragment) (int64, error) {
	return dbSaveFragment(frag)
}

func (a *App) LoadCreations(page, pageSize int) (*PaginatedResult, error) {
	creations, total, err := dbLoadCreations(page, pageSize)
	if err != nil {
		return nil, err
	}
	return paginatedSlice(creations, total, page, pageSize), nil
}

func (a *App) SaveCreation(content string) (*Creation, error) {
	id, createdAt, err := dbSaveCreation(content)
	if err != nil {
		return nil, err
	}

	return &Creation{
		ID:        id,
		Content:   content,
		CreatedAt: createdAt,
	}, nil
}

func (a *App) ClearCreations() error {
	return dbClearCreations()
}

func (a *App) ClearCollected() error {
	return dbClearCollected()
}

func (a *App) ResetGame() error {
	if err := dbClearCreations(); err != nil {
		return err
	}
	return dbClearCollected()
}
